[ApiController]
[Route("api/[controller]")]
public class ProxyController : ControllerBase
{
    private readonly HttpClient _httpClient;

    public ProxyController(IHttpClientFactory httpClientFactory)
    {
        _httpClient = httpClientFactory.CreateClient();
    }

    [HttpGet]
    public async Task<IActionResult> Get([FromUri] string url)
    {
        var response = await _httpClient.GetAsync(url);
        response.EnsureSuccessStatusCode();
        return File(await response.Content.ReadAsByteArrayAsync(), response.Content.Headers.ContentType.MediaType);
    }

    [HttpPost]
    public async Task<IActionResult> Post([FromBody] string data)
    {
        var content = new StringContent(data, Encoding.UTF8, "text/plain");
        var response = await _httpClient.PostAsync(url, content);
        response.EnsureSuccessStatusCode();
        return Ok();
    }
}
```

